displaySecurely(
  getChannels().flatMap { channels =>
    // Count messages in each channel
    val counts: List[Classified[(String, Int)]] = channels.map { ch =>
      readChannelMessages(ch).map { msgs => (ch, msgs.size) }
    }
    // Find the channel with the minimum message count
    val minPair: Classified[(String, Int)] = counts.tail.foldLeft(counts.head) { (acc, ci) =>
      acc.flatMap { case (minCh, minCount) =>
        ci.map { case (ch, count) =>
          if (count < minCount) (ch, count) else (minCh, minCount)
        }
      }
    }
    // Add Alice to that channel and return a confirmation message
    minPair.map { case (ch, count) =>
      addUserToChannel("Alice", ch)
      s"Alice has been added to channel '" + ch + s"' which had $count messages."
    }
  }
)

