displaySecurely(
  getChannels().flatMap { channels =>
    if (channels.isEmpty) {
      // No channels to choose from
      getWebpage("about:blank").map(_ => "No channels available to add Alice.")
    } else {
      // Start by mapping first channel to a string "channel::count"
      val initial = readChannelMessages(channels.head).map { msgs =>
        channels.head + "::" + msgs.size
      }
      // Fold over the rest to find the channel with the fewest messages
      val minStr = channels.tail.foldLeft(initial) { (acc, ch) =>
        acc.flatMap { prev =>
          readChannelMessages(ch).map { msgs =>
            val prevCnt = prev.split("::")(1).toInt
            val cnt = msgs.size
            if (cnt < prevCnt) ch + "::" + cnt else prev
          }
        }
      }
      // Parse out the result, add Alice, and report
      minStr.map { ms =>
        val parts = ms.split("::")
        val minCh = parts(0)
        val minCnt = parts(1)
        addUserToChannel("Alice", minCh)
        "Alice has been added to channel '" + minCh + "' which had " + minCnt + " messages."
      }
    }
  }
)

