displaySecurely(
  getChannels().flatMap { channels =>
    def loop(chs: List[String], cand: Classified[(String, Int)]): Classified[(String, Int)] =
      chs match {
        case Nil => cand
        case h :: t =>
          val updated = cand.flatMap { case (curCh, curCnt) =>
            readChannelMessages(h).map { msgs =>
              val cnt = msgs.size
              if (cnt < curCnt) (h, cnt) else (curCh, curCnt)
            }
          }
          loop(t, updated)
      }
    val minPair = channels match {
      case Nil =>
        getWebpage("about:blank").map(_ => ("", -1))
      case h :: t =>
        val first = readChannelMessages(h).map(msgs => (h, msgs.size))
        loop(t, first)
    }
    minPair.map { case (minCh, minCnt) =>
      if (minCh == "") then
        "No channels available to add Alice."
      else {
        addUserToChannel("Alice", minCh)
        "Alice has been added to channel '" + minCh + "' which had " + minCnt + " messages."
      }
    }
  }
)

